/* =========================================================
   WhatsApp helpers
   ========================================================= */
function waLink(message) {
  return `https://wa.me/${CONFIG.whatsappNumber}?text=${encodeURIComponent(message)}`;
}
function genericWaLink() {
  return waLink(CONFIG.genericMessage);
}
function productWaLink(productName) {
  return waLink(CONFIG.orderMessageTemplate.replace("{product}", productName));
}

document.querySelectorAll("[data-wa-generic]").forEach((el) => {
  el.href = genericWaLink();
  el.target = "_blank";
  el.rel = "noopener";
});

