/* =========================================================
   Testimonianze — slider automatico
   ========================================================= */
const tTrack = document.getElementById("tTrack");
const tDotsWrap = document.getElementById("tDots");
TESTIMONIALS.forEach((t) => {
  const card = document.createElement("div");
  card.className = "t-card reveal";
  card.innerHTML = `
    <div class="t-stars">
      ${Array(5).fill('<svg viewBox="0 0 24 24"><path d="M12 2l3.1 6.3 6.9 1-5 4.9 1.2 6.9-6.2-3.3-6.2 3.3 1.2-6.9-5-4.9 6.9-1z"/></svg>').join("")}
    </div>
    <p class="t-quote">"${t.quote}"</p>
    <div class="t-person">
      <div class="t-avatar" style="background:${t.color}">${t.initials}</div>
      <div><b>${t.name}</b><span>${t.role}</span></div>
    </div>
  `;
  tTrack.appendChild(card);
});
TESTIMONIALS.forEach((_, i) => {
  const dot = document.createElement("button");
  if (i === 0) dot.classList.add("active");
  dot.addEventListener("click", () => goToSlide(i));
  tDotsWrap.appendChild(dot);
});
let tIndex = 0;
function goToSlide(i) {
  tIndex = i;
  const cardWidth = tTrack.children[0].getBoundingClientRect().width + 24;
  tTrack.style.transform = `translateX(-${cardWidth * i}px)`;
  [...tDotsWrap.children].forEach((d, idx) => d.classList.toggle("active", idx === i));
}
let tAutoplay = setInterval(() => {
  goToSlide((tIndex + 1) % TESTIMONIALS.length);
}, 4500);
tTrack.addEventListener("mouseenter", () => clearInterval(tAutoplay));
tTrack.addEventListener("mouseleave", () => {
  tAutoplay = setInterval(() => goToSlide((tIndex + 1) % TESTIMONIALS.length), 4500);
});

/* =========================================================
   FAQ accordion
   ========================================================= */
const faqList = document.getElementById("faqList");
FAQS.forEach((f) => {
  const item = document.createElement("div");
  item.className = "faq-item";
  item.innerHTML = `
    <button class="faq-q"><span>${f.q}</span><span class="plus"></span></button>
    <div class="faq-a"><p>${f.a}</p></div>
  `;
  const btn = item.querySelector(".faq-q");
  const answer = item.querySelector(".faq-a");
  btn.addEventListener("click", () => {
    const isOpen = item.classList.contains("open");
    faqList.querySelectorAll(".faq-item").forEach((other) => {
      other.classList.remove("open");
      other.querySelector(".faq-a").style.maxHeight = null;
    });
    if (!isOpen) {
      item.classList.add("open");
      answer.style.maxHeight = answer.scrollHeight + "px";
    }
  });
  faqList.appendChild(item);
});

/* =========================================================
   Navbar scroll state + mobile menu
   ========================================================= */
const navbar = document.getElementById("navbar");
